sw_js = "// Droidify Service Worker\n// No caching — all requests go to network.\n// Exists for: PWA installability + Background Sync (offline search queue)\n\nconst SYNC_TAG = 'droidify-search-sync';\n\nself.addEventListener('install',  () => self.skipWaiting());\n\nself.addEventListener('activate', e => e.waitUntil(\n  // Delete any old caches from previous versions\n  caches.keys()\n    .then(keys => Promise.all(keys.map(k => caches.delete(k))))\n    .then(() => self.clients.claim())\n));\n\n// All fetches go straight to network — no cache reads or writes\nself.addEventListener('fetch', event => {\n  if (event.request.method !== 'GET') return;\n  event.respondWith(fetch(event.request));\n});\n\n// Background Sync — retries queued searches when connection is restored\n// Queued by the client when a search fails offline\nself.addEventListener('sync', event => {\n  if (event.tag === SYNC_TAG) {\n    event.waitUntil(flushSearchQueue());\n  }\n});\n\nasync function flushSearchQueue() {\n  // Nothing to flush server-side — just notify clients that sync fired\n  // so they can retry their last search\n  const clients = await self.clients.matchAll({ type: 'window' });\n  clients.forEach(c => c.postMessage({ type: 'SYNC_COMPLETE', tag: SYNC_TAG }));\n}\n\n// Periodic Background Sync — refresh device/ROM index in background\n// Requires 'periodic-background-sync' permission (granted by browser heuristic)\nself.addEventListener('periodicsync', event => {\n  if (event.tag === 'droidify-refresh') {\n    event.waitUntil(prefetchStats());\n  }\n});\n\nasync function prefetchStats() {\n  try {\n    // Warm the server-side cache so first load is fast\n    await fetch('/api/devices?limit=1');\n    await fetch('/api/roms?limit=1');\n  } catch (_) { /* offline — skip */ }\n}\n\nself.addEventListener('message', event => {\n  if (event.data?.type === 'SKIP_WAITING') self.skipWaiting();\n});\n"

